#include <stdio.h>
#include <stdlib.h>

int find(int* parent, int x) {
    if (parent[x] == x) return x;
    return parent[x] = find(parent, parent[x]);
}

void unite(int* parent, int a, int b) {
    a = find(parent, a);
    b = find(parent, b);
    if (a != b) parent[b] = a;
}

int maxStonesRemoved(int** stones, int n) {
    int* parent = (int*)malloc((n + 10005) * sizeof(int));
    for (int i = 0; i < n + 10005; i++) parent[i] = i;
    for (int i = 0; i < n; i++) {
        int r = stones[i][0];
        int c = stones[i][1] + 10000;
        unite(parent, r, c);
    }
    int compCount = 0;
    int seen[n + 10005] = {0};
    for (int i = 0; i < n; i++) {
        int root = find(parent, stones[i][0]);
        if (!seen[root]) {
            seen[root] = 1;
            compCount++;
        }
    }
    free(parent);
    return n - compCount;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int n;
        scanf("%d", &n);
        int** stones = (int**)malloc(n * sizeof(int*));
        for (int i = 0; i < n; i++) {
            stones[i] = (int*)malloc(2 * sizeof(int));
            scanf("%d %d", &stones[i][0], &stones[i][1]);
        }
        printf("%d\n", maxStonesRemoved(stones, n));
        for (int i = 0; i < n; i++) free(stones[i]);
        free(stones);
    }
    return 0;
}

