#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    unordered_map<int, int> parent;

    int find(int x) {
        if (parent[x] == x) return x;
        return parent[x] = find(parent[x]);
    }

    void unite(int a, int b) {
        a = find(a);
        b = find(b);
        if (a != b) parent[b] = a;
    }

    int maxStonesRemoved(vector<vector<int>>& stones) {
        parent.clear();
        const int OFFSET = 10000;
        for (auto& s : stones) {
            int r = s[0];
            int c = s[1] + OFFSET;
            if (!parent.count(r)) parent[r] = r;
            if (!parent.count(c)) parent[c] = c;
            unite(r, c);
        }
        unordered_set<int> components;
        for (auto& s : stones) {
            components.insert(find(s[0]));
        }
        return stones.size() - components.size();
    }
};

int main() {
    int T;
    cin >> T;
    for (int t = 0; t < T; t++) {
        int n;
        cin >> n;
        vector<vector<int>> stones(n, vector<int>(2));
        for (int i = 0; i < n; i++) {
            cin >> stones[i][0] >> stones[i][1];
        }
        Solution solution;
        cout << solution.maxStonesRemoved(stones) << endl;
    }
    return 0;
}

