import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Scanner;
import java.util.Set;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int n = scanner.nextInt();
            int[][] stones = new int[n][2];
            for (int i = 0; i < n; i++) {
                stones[i][0] = scanner.nextInt();
                stones[i][1] = scanner.nextInt();
            }
            System.out.println(maxStonesRemoved(stones));
        }
    }

    public static int maxStonesRemoved(int[][] stones) {
        Map<Integer, Integer> parent = new HashMap<>();
        final int OFFSET = 10000;
        for (int[] s : stones) {
            int r = s[0];
            int c = s[1] + OFFSET;
            parent.putIfAbsent(r, r);
            parent.putIfAbsent(c, c);
            union(parent, r, c);
        }
        Set<Integer> components = new HashSet<>();
        for (int[] s : stones) {
            components.add(find(parent, s[0]));
        }
        return stones.length - components.size();
    }

    private static int find(Map<Integer, Integer> parent, int x) {
        if (parent.get(x) != x) {
            parent.put(x, find(parent, parent.get(x)));
        }
        return parent.get(x);
    }

    private static void union(Map<Integer, Integer> parent, int a, int b) {
        int pa = find(parent, a);
        int pb = find(parent, b);
        if (pa != pb) {
            parent.put(pb, pa);
        }
    }
}

